// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";

/**
 * @title ProvenanceContract
 * @dev Smart contract for tracking complete supply chain provenance
 */
contract ProvenanceContract is Ownable {
    
    enum Stage {
        FARMING,
        HARVESTED,
        PROCESSED,
        PACKAGED,
        IN_TRANSIT,
        DELIVERED,
        RETAIL
    }

    struct ProvenanceRecord {
        uint256 productId;
        uint256 auctionId;
        uint256 shipmentId;
        address farmer;
        address distributor;
        address retailer;
        string crop;
        string variety;
        uint256 quantity;
        string qualityGrade;
        uint256 qualityConfidence;
        string farmLocation;
        uint256 harvestDate;
        uint256 expiryDate;
        string[] certifications; // Organic, Fair Trade, etc.
        string qrCodeHash;
        bool isActive;
    }

    struct StageRecord {
        Stage stage;
        address actor;
        uint256 timestamp;
        string location;
        string notes;
        string[] evidenceHashes; // IPFS hashes for images/documents
        string temperature;
        string humidity;
    }

    mapping(uint256 => ProvenanceRecord) public products;
    mapping(uint256 => StageRecord[]) public productStageHistory;
    mapping(string => uint256) public qrCodeToProduct;
    mapping(address => uint256[]) public actorProducts;
    
    uint256 private _productIdCounter;

    event ProductCreated(
        uint256 indexed productId,
        address indexed farmer,
        string crop,
        uint256 auctionId,
        string qrCodeHash
    );

    event StageUpdated(
        uint256 indexed productId,
        Stage indexed stage,
        address indexed actor,
        uint256 timestamp
    );

    event QualityVerified(
        uint256 indexed productId,
        string qualityGrade,
        uint256 confidence,
        address verifier
    );

    event OwnershipTransferred(
        uint256 indexed productId,
        address indexed from,
        address indexed to,
        Stage stage
    );

    modifier onlyProductActor(uint256 productId) {
        ProvenanceRecord memory product = products[productId];
        require(
            msg.sender == product.farmer || 
            msg.sender == product.distributor || 
            msg.sender == product.retailer ||
            msg.sender == owner(),
            "Not authorized for this product"
        );
        _;
    }

    modifier productExists(uint256 productId) {
        require(products[productId].isActive, "Product does not exist");
        _;
    }

    constructor() Ownable(msg.sender) {}

    /**
     * @dev Create a new product record
     */
    function createProduct(
        uint256 _auctionId,
        string memory _crop,
        string memory _variety,
        uint256 _quantity,
        string memory _qualityGrade,
        uint256 _qualityConfidence,
        string memory _farmLocation,
        uint256 _harvestDate,
        uint256 _expiryDate,
        string[] memory _certifications,
        string memory _qrCodeHash
    ) external returns (uint256) {
        require(bytes(_crop).length > 0, "Crop name cannot be empty");
        require(_quantity > 0, "Quantity must be greater than 0");
        require(bytes(_qrCodeHash).length > 0, "QR code hash cannot be empty");
        require(qrCodeToProduct[_qrCodeHash] == 0, "QR code already exists");

        uint256 productId = _productIdCounter++;
        
        products[productId] = ProvenanceRecord({
            productId: productId,
            auctionId: _auctionId,
            shipmentId: 0, // Will be set later when shipping starts
            farmer: msg.sender,
            distributor: address(0),
            retailer: address(0),
            crop: _crop,
            variety: _variety,
            quantity: _quantity,
            qualityGrade: _qualityGrade,
            qualityConfidence: _qualityConfidence,
            farmLocation: _farmLocation,
            harvestDate: _harvestDate,
            expiryDate: _expiryDate,
            certifications: _certifications,
            qrCodeHash: _qrCodeHash,
            isActive: true
        });

        qrCodeToProduct[_qrCodeHash] = productId;
        actorProducts[msg.sender].push(productId);

        // Add initial farming stage
        addStageRecord(
            productId, 
            Stage.FARMING, 
            _farmLocation, 
            "Product created and farming stage initiated",
            new string[](0),
            "",
            ""
        );

        emit ProductCreated(productId, msg.sender, _crop, _auctionId, _qrCodeHash);
        
        return productId;
    }

    /**
     * @dev Add a stage record to product history
     */
    function addStageRecord(
        uint256 _productId,
        Stage _stage,
        string memory _location,
        string memory _notes,
        string[] memory _evidenceHashes,
        string memory _temperature,
        string memory _humidity
    ) public productExists(_productId) onlyProductActor(_productId) {
        
        StageRecord memory newStage = StageRecord({
            stage: _stage,
            actor: msg.sender,
            timestamp: block.timestamp,
            location: _location,
            notes: _notes,
            evidenceHashes: _evidenceHashes,
            temperature: _temperature,
            humidity: _humidity
        });

        productStageHistory[_productId].push(newStage);

        emit StageUpdated(_productId, _stage, msg.sender, block.timestamp);
    }

    /**
     * @dev Update product to harvested stage
     */
    function markHarvested(
        uint256 _productId,
        string memory _location,
        string memory _notes,
        string[] memory _evidenceHashes
    ) external {
        addStageRecord(_productId, Stage.HARVESTED, _location, _notes, _evidenceHashes, "", "");
    }

    /**
     * @dev Update product to processed stage
     */
    function markProcessed(
        uint256 _productId,
        string memory _location,
        string memory _notes,
        string[] memory _evidenceHashes,
        string memory _temperature
    ) external {
        addStageRecord(_productId, Stage.PROCESSED, _location, _notes, _evidenceHashes, _temperature, "");
    }

    /**
     * @dev Update product to packaged stage
     */
    function markPackaged(
        uint256 _productId,
        string memory _location,
        string memory _notes,
        string[] memory _evidenceHashes
    ) external {
        addStageRecord(_productId, Stage.PACKAGED, _location, _notes, _evidenceHashes, "", "");
    }

    /**
     * @dev Transfer product to distributor and mark in transit
     */
    function transferToDistributor(
        uint256 _productId,
        address _distributor,
        uint256 _shipmentId,
        string memory _notes
    ) external productExists(_productId) {
        require(msg.sender == products[_productId].farmer, "Only farmer can transfer to distributor");
        require(_distributor != address(0), "Invalid distributor address");

        products[_productId].distributor = _distributor;
        products[_productId].shipmentId = _shipmentId;
        actorProducts[_distributor].push(_productId);

        addStageRecord(_productId, Stage.IN_TRANSIT, "In Transit", _notes, new string[](0), "", "");

        emit OwnershipTransferred(_productId, msg.sender, _distributor, Stage.IN_TRANSIT);
    }

    /**
     * @dev Mark product as delivered and transfer to retailer
     */
    function transferToRetailer(
        uint256 _productId,
        address _retailer,
        string memory _deliveryLocation,
        string memory _notes
    ) external productExists(_productId) {
        require(msg.sender == products[_productId].distributor, "Only distributor can transfer to retailer");
        require(_retailer != address(0), "Invalid retailer address");

        products[_productId].retailer = _retailer;
        actorProducts[_retailer].push(_productId);

        addStageRecord(_productId, Stage.DELIVERED, _deliveryLocation, _notes, new string[](0), "", "");

        emit OwnershipTransferred(_productId, msg.sender, _retailer, Stage.DELIVERED);
    }

    /**
     * @dev Mark product as available at retail
     */
    function markRetailAvailable(
        uint256 _productId,
        string memory _retailLocation,
        string memory _notes
    ) external productExists(_productId) {
        require(msg.sender == products[_productId].retailer, "Only retailer can mark retail available");

        addStageRecord(_productId, Stage.RETAIL, _retailLocation, _notes, new string[](0), "", "");
    }

    /**
     * @dev Verify product quality (can be done by any authorized actor)
     */
    function verifyQuality(
        uint256 _productId,
        string memory _newQualityGrade,
        uint256 _newConfidence,
        string memory _notes
    ) external productExists(_productId) onlyProductActor(_productId) {
        products[_productId].qualityGrade = _newQualityGrade;
        products[_productId].qualityConfidence = _newConfidence;

        // Add quality verification as a stage record
        string[] memory evidenceHashes = new string[](0);
        addStageRecord(_productId, getCurrentStage(_productId), "Quality Verification", _notes, evidenceHashes, "", "");

        emit QualityVerified(_productId, _newQualityGrade, _newConfidence, msg.sender);
    }

    /**
     * @dev Get product by QR code hash
     */
    function getProductByQR(string memory _qrCodeHash) 
        external 
        view 
        returns (ProvenanceRecord memory) 
    {
        uint256 productId = qrCodeToProduct[_qrCodeHash];
        require(productId != 0 || (productId == 0 && products[0].isActive), "Product not found");
        
        return products[productId];
    }

    /**
     * @dev Get complete product history
     */
    function getProductHistory(uint256 _productId) 
        external 
        view 
        returns (StageRecord[] memory) 
    {
        return productStageHistory[_productId];
    }

    /**
     * @dev Get current stage of product
     */
    function getCurrentStage(uint256 _productId) 
        public 
        view 
        returns (Stage) 
    {
        StageRecord[] memory history = productStageHistory[_productId];
        if (history.length == 0) return Stage.FARMING;
        
        return history[history.length - 1].stage;
    }

    /**
     * @dev Get products for an actor (farmer, distributor, retailer)
     */
    function getActorProducts(address _actor) 
        external 
        view 
        returns (uint256[] memory) 
    {
        return actorProducts[_actor];
    }

    /**
     * @dev Get total products count
     */
    function getTotalProducts() external view returns (uint256) {
        return _productIdCounter;
    }

    /**
     * @dev Check if product is expired
     */
    function isProductExpired(uint256 _productId) 
        external 
        view 
        productExists(_productId) 
        returns (bool) 
    {
        return block.timestamp > products[_productId].expiryDate;
    }

    /**
     * @dev Get stage name as string
     */
    function getStageString(Stage _stage) external pure returns (string memory) {
        if (_stage == Stage.FARMING) return "Farming";
        if (_stage == Stage.HARVESTED) return "Harvested";
        if (_stage == Stage.PROCESSED) return "Processed";
        if (_stage == Stage.PACKAGED) return "Packaged";
        if (_stage == Stage.IN_TRANSIT) return "In Transit";
        if (_stage == Stage.DELIVERED) return "Delivered";
        if (_stage == Stage.RETAIL) return "Retail";
        return "Unknown";
    }
}

